#include <iostream>

using namespace std;

int main()
{
    int *ptr = new int(25);

    cout << *ptr << endl;

    delete ptr;

    return 0;
}

int *scores = new int[5];

// ... use scores ...

delete[] scores; // note the [] — required for array allocations

int *ptr = new int(25);
delete ptr;

cout << *ptr; // DANGER — ptr still holds the old address, but that memory is no longer valid

#include <iostream>

using namespace std;

int main()
{
    int *ptr = new int(25);

    delete ptr;
    ptr = nullptr; // ptr no longer dangles

    if (ptr == nullptr)
    {
        cout << "ptr is safely null." << endl;
    }

    return 0;
}

int *ptr = new int(25);

